import { isValidStudioRoute } from "./studioRoutes.js";
/** The Studio home, opened whenever no specific (valid) route is requested. */
export const DEFAULT_STUDIO_PATH = "/studio";
/**
 * Normalize an initial Studio path to a route we're allowed to open. A valid
 * `/studio*` route passes through unchanged; anything missing or disallowed
 * falls back to the Studio home. Never throws: opening the safe default beats
 * failing a flow (e.g. a sign-in) on an unexpected path. Shared by every
 * window-open site (DirectChannel keyless open and the daemon) so they agree.
 */
export function resolveStudioInitialPath(input) {
    if (input && isValidStudioRoute(input)) {
        return input;
    }
    return DEFAULT_STUDIO_PATH;
}
/**
 * Build the session-scoped Studio URL. Idempotent: if the path already carries
 * a `session=` param it is returned as-is; otherwise the session id is appended
 * with the correct separator. Shared so the URL shape can never drift between
 * the direct and daemon open paths.
 */
export function buildStudioSessionUrl(args) {
    const { serviceUrl, path, sessionId } = args;
    if (path.includes("session=")) {
        return `${serviceUrl}${path}`;
    }
    const separator = path.includes("?") ? "&" : "?";
    return `${serviceUrl}${path}${separator}session=${encodeURIComponent(sessionId)}`;
}
